// NewClient returns *argocd.Client using MCP-backed endpoints.
func NewClient(
	scheme string,
	host string,
	doer goahttp.Doer,
	enc func(*http.Request) goahttp.Encoder,
	dec func(*http.Response) goahttp.Decoder,
	restore bool,
) *argocd.Client {
	e := NewEndpoints(scheme, host, doer, enc, dec, restore)
	return argocd.NewClient(
		e.ListApplications,
		e.GetApplication,
		e.GetApplicationResourceTree,
		e.GetApplicationManagedResources,
		e.GetApplicationWorkloadLogs,
		e.GetApplicationEvents,
		e.GetResourceEvents,
		e.GetResources,
		e.GetResourceActions,
		e.CreateApplication,
		e.UpdateApplication,
		e.DeleteApplication,
		e.SyncApplication,
		e.RunResourceAction,
	)
}
